 15→/// Wrapper around fastembed's `TextEmbedding` model.
 16→/// Uses GTE multilingual base int8 loaded from disk.
 17→pub struct Embedder {
 18→    model: TextEmbedding,
 19→}
 20→
 21→impl Embedder {
 22→    /// Create a new embedder by loading GTE multilingual base int8 from disk.
 23→    ///
 24→    /// Expected files in `model_cache_dir/gte-multilingual-base/`:
 25→    ///   - `model_int8.onnx`
 26→    ///   - `tokenizer.json`
 27→    ///   - `config.json`
 28→    ///   - `special_tokens_map.json`
 29→    ///   - `tokenizer_config.json`
 30→    ///
 31→    /// If the model files are not found, returns an error instructing the user
 32→    /// to run `mementor model download`.
 33→    pub fn new(model_cache_dir: &Path) -> anyhow::Result<Self> {
 34→        let base = model_cache_dir.join(MODEL_SUBDIR);
 35→
 36→        let onnx_bytes = fs::read(base.join(MODEL_ONNX_FILE)).with_context(|| {
 37→            format!(
 38→                "Model not found at {}. Run 'mementor model download' first.",
 39→                base.display()
 40→            )
 41→        })?;
 42→
 43→        let tokenizer_files = TokenizerFiles {
 44→            tokenizer_file: fs::read(base.join(MODEL_TOKENIZER_FILE))
 45→                .context("Missing tokenizer.json")?,
 46→            config_file: fs::read(base.join(MODEL_CONFIG_FILE)).context("Missing config.json")?,
 47→            special_tokens_map_file: fs::read(base.join(MODEL_SPECIAL_TOKENS_FILE))
 48→                .context("Missing special_tokens_map.json")?,
 49→            tokenizer_config_file: fs::read(base.join(MODEL_TOKENIZER_CONFIG_FILE))
 50→                .context("Missing tokenizer_config.json")?,
 51→        };
 52→
 53→        let user_model =
 54→            UserDefinedEmbeddingModel::new(onnx_bytes, tokenizer_files).with_pooling(Pooling::Cls);
 55→
 56→        let model =
 57→            TextEmbedding::try_new_from_user_defined(user_model, InitOptionsUserDefined::default())
 58→                .context("Failed to initialize GTE multilingual base int8 model")?;
 59→
 60→        Ok(Self { model })
 61→    }
 62→
 63→    /// Access the tokenizer used by the embedding model.
 64→    pub fn tokenizer(&self) -> &Tokenizer {
 65→        &self.model.tokenizer
 66→    }
 67→
 68→    /// Embed a batch of text strings and return their vector representations.
 69→    pub fn embed_batch(&mut self, texts: &[&str]) -> anyhow::Result<Vec<Vec<f32>>> {
 70→        let owned: Vec<String> = texts.iter().copied().map(String::from).collect();
 71→        let embeddings = self
 72→            .model
 73→            .embed(owned, None)
 74→            .context("Failed to embed texts")?;
 75→        Ok(embeddings)
 76→    }
 77→
 78→    /// Load only the tokenizer without initializing the ONNX model.
 79→    ///
 80→    /// Useful when only tokenization is needed (e.g., chunking) and the full
 81→    /// model initialization overhead is unnecessary.
 82→    pub fn load_tokenizer(model_cache_dir: &Path) -> anyhow::Result<Tokenizer> {
 83→        let path = model_cache_dir
 84→            .join(MODEL_SUBDIR)
 85→            .join(MODEL_TOKENIZER_FILE);
 86→        Tokenizer::from_file(&path)
 87→            .map_err(|e| anyhow::anyhow!("Failed to load tokenizer from {}: {e}", path.display()))
 88→    }
 89→
 90→    /// Return the embedding dimension (768 for GTE multilingual base).
 91→    #[must_use]
 92→    pub const fn dimension() -> usize {
 93→        EMBEDDING_DIMENSION
 94→    }
 95→}
