 4→/// Initialize a git repository with a test user config and an initial empty
 5→/// commit.
 6→pub fn init_git_repo(dir: &Path) {
 7→    run_git(dir, &["init"]);
 8→    run_git(dir, &["config", "user.email", "test@test.com"]);
 9→    run_git(dir, &["config", "user.name", "Test"]);
10→    run_git(dir, &["commit", "--allow-empty", "-m", "initial"]);
11→}
12→
13→/// Run a git command in the given directory.
14→///
15→/// Passes `-c protocol.file.allow=always` to allow file-protocol operations
16→/// (required for submodule clones in tests on Git 2.38.1+).
17→///
18→/// # Panics
19→///
20→/// Panics if the command fails to start or exits with a non-zero status.
21→pub fn run_git(dir: &Path, args: &[&str]) {
22→    let output = Command::new("git")
23→        .args(["-c", "protocol.file.allow=always"])
24→        .args(args)
25→        .current_dir(dir)
26→        .output()
27→        .expect("git command failed to start");
28→    assert!(
29→        output.status.success(),
30→        "git {} failed in {}: {}",
31→        args.join(" "),
32→        dir.display(),
33→        String::from_utf8_lossy(&output.stderr),
34→    );
35→}
36→
37→/// Assert that two paths are equal after canonicalization.
38→///
39→/// Resolves symlinks before comparison, avoiding false negatives from macOS
40→/// `/private/tmp` vs `/tmp` aliasing.
41→///
42→/// # Panics
43→///
44→/// Panics if either path cannot be canonicalized or if the paths differ.
45→pub fn assert_paths_eq(actual: &Path, expected: &Path) {
46→    let actual = std::fs::canonicalize(actual)
47→        .unwrap_or_else(|_| panic!("cannot canonicalize {}", actual.display()));
48→    let expected = std::fs::canonicalize(expected)
49→        .unwrap_or_else(|_| panic!("cannot canonicalize {}", expected.display()));
50→    assert_eq!(actual, expected);
51→}
