 38→/// Strip margin markers from a multi-line string (Kotlin-style `trimMargin`).
 39→///
 40→/// Each line is scanned for the first `|` character after optional leading
 41→/// whitespace. Everything before and including the `|` is removed. Lines that
 42→/// do not contain a leading `|` are dropped.
 43→///
 44→/// Use `\|` to include a literal `|` in the output.
 45→///
 46→/// Prefer the [`trim_margin!`] macro which wraps `format!` for convenience.
 47→pub fn _trim_margin(s: &str) -> String {
 48→    s.lines()
 49→        .filter_map(|line| {
 50→            let trimmed = line.trim_start();
 51→            trimmed
 52→                .strip_prefix('|')
 53→                .map(|rest| rest.replace("\\|", "|"))
 54→        })
 55→        .collect::<Vec<_>>()
 56→        .join("\n")
 57→}
 58→
 59→/// Build a margin-trimmed string with `format!`-style interpolation.
 60→///
 61→/// Each line must start with optional whitespace followed by `|`. The `|` and
 62→/// all preceding whitespace are stripped. Use `\|` for a literal pipe character.
 63→///
 64→/// # Example
 65→///
 66→/// ```ignore
 67→/// let name = "world";
 68→/// let s = trim_margin!(
 69→///     "|Hello, {name}!
 70→///      |  indented line
 71→///      |done
 72→///      |"
 73→/// );
 74→/// assert_eq!(s, "Hello, world!\n  indented line\ndone\n");
 75→/// ```
 76→macro_rules! trim_margin {
 77→    ($fmt:literal $(, $arg:expr)* $(,)?) => {
 78→        $crate::test_util::_trim_margin(&format!($fmt $(, $arg)*))
 79→    };
 80→}
 81→pub(crate) use trim_margin;
 82→
 83→#[cfg(test)]
 84→mod tests {
 85→    use super::_trim_margin;
 86→
 87→    #[test]
 88→    fn trim_margin_basic() {
 89→        let result = _trim_margin(
 90→            "|line one
 91→             |  line two
 92→             |line three",
 93→        );
 94→        assert_eq!(result, "line one\n  line two\nline three");
 95→    }
 96→
 97→    #[test]
 98→    fn trim_margin_trailing_newline() {
 99→        let result = _trim_margin(
100→            "|hello
101→             |",
102→        );
103→        assert_eq!(result, "hello\n");
104→    }
105→
106→    #[test]
107→    fn trim_margin_escaped_pipe() {
108→        let result = _trim_margin(
109→            "|a \\| b
110→             |c",
111→        );
112→        assert_eq!(result, "a | b\nc");
113→    }
114→
115→    #[test]
116→    fn trim_margin_skips_lines_without_pipe() {
117→        let result = _trim_margin(
118→            "no pipe here
119→             |has pipe",
120→        );
121→        assert_eq!(result, "has pipe");
122→    }
123→
124→    #[test]
125→    fn trim_margin_with_format() {
126→        let name = "world";
127→        let s = trim_margin!(
128→            "|Hello, {name}!
129→             |  indented
130→             |"
131→        );
132→        assert_eq!(s, "Hello, world!\n  indented\n");
133→    }
134→}
