 1→use std::io::Write;
 2→use std::path::{Path, PathBuf};
 3→use std::sync::atomic::{AtomicUsize, Ordering};
 4→
 5→/// Counter for generating deterministic, unique UUIDs in test transcript entries.
 6→static ENTRY_COUNTER: AtomicUsize = AtomicUsize::new(0);
 7→
 8→/// Build a single JSONL transcript entry for a given role and text.
 9→///
10→/// Returns a JSON string suitable for writing to a transcript file.
11→/// Each call produces a unique UUID via an atomic counter.
12→pub fn make_entry(role: &str, text: &str) -> String {
13→    let id = ENTRY_COUNTER.fetch_add(1, Ordering::Relaxed);
14→    serde_json::json!({
15→        "type": "message",
16→        "uuid": format!("uuid-{id}"),
17→        "sessionId": "test-session",
18→        "timestamp": "2026-01-01T00:00:00Z",
19→        "message": {
20→            "role": role,
21→            "content": text
22→        }
23→    })
24→    .to_string()
25→}
26→
27→/// Build a `pr-link` type JSONL transcript entry (no `message` field).
28→///
29→/// Returns a JSON string suitable for writing to a transcript file.
30→pub fn make_pr_link_entry(
31→    session_id: &str,
32→    pr_number: u32,
33→    pr_url: &str,
34→    pr_repository: &str,
35→) -> String {
36→    serde_json::json!({
37→        "type": "pr-link",
38→        "sessionId": session_id,
39→        "prNumber": pr_number,
40→        "prUrl": pr_url,
41→        "prRepository": pr_repository,
42→        "timestamp": "2026-02-17T00:00:00Z"
43→    })
44→    .to_string()
45→}
46→
47→/// Write JSONL lines to a transcript file in the given directory.
48→///
49→/// Returns the path to the created `transcript.jsonl` file.
50→pub fn write_transcript(dir: &Path, lines: &[&str]) -> PathBuf {
51→    let path = dir.join("transcript.jsonl");
52→    let mut f = std::fs::File::create(&path).unwrap();
53→    for line in lines {
54→        writeln!(f, "{line}").unwrap();
55→    }
56→    path
57→}
