  9→
 10→/// Real implementation that uses actual stdin/stdout/stderr.
 11→pub struct StdIO {
 12→    stdin: Stdin,
 13→    stdout: Stdout,
 14→    stderr: Stderr,
 15→}
 16→
 17→impl StdIO {
 18→    #[must_use]
 19→    pub fn new() -> Self {
