260→impl Content {
261→    /// Extract all text content from `text` and `thinking` blocks.
262→    /// Skips `tool_use`, `tool_result`, and unknown block types.
263→    pub fn extract_text(&self) -> String {
264→        match self {
265→            Content::Text(s) => s.clone(),
266→            Content::Blocks(blocks) => {
267→                let texts: Vec<&str> = blocks
268→                    .iter()
269→                    .filter_map(|block| match block {
270→                        ContentBlock::Text { text } => Some(text.as_str()),
271→                        ContentBlock::Thinking { thinking, .. } => {
272→                            thinking.as_deref().filter(|s| !s.is_empty())
273→                        }
274→                        ContentBlock::ToolUse { .. }
275→                        | ContentBlock::ToolResult { .. }
276→                        | ContentBlock::Unknown => None,
277→                    })
278→                    .collect();
279→                texts.join("\n\n")
280→            }
281→        }
282→    }
283→
284→    /// Extract compact tool summaries from `tool_use` blocks.
285→    /// Returns one summary string per tool invocation, skipping tools with no
286→    /// useful search signal (e.g., `TaskCreate`, `AskUserQuestion`).
287→    pub fn extract_tool_summary(&self) -> Vec<String> {
288→        match self {
289→            Content::Text(_) => vec![],
290→            Content::Blocks(blocks) => blocks
291→                .iter()
292→                .filter_map(|block| {
293→                    let ContentBlock::ToolUse { name, input, .. } = block else {
294→                        return None;
295→                    };
296→                    let name = name.as_deref()?;
297→                    let summary = summarize_tool(name, input.as_ref());
298→                    (!summary.is_empty()).then_some(summary)
299→                })
300→                .collect(),
301→        }
302→    }
303→
304→    /// Returns `true` if any content block deserialized as `Unknown`.
305→    pub fn has_unknown_blocks(&self) -> bool {
306→        match self {
307→            Content::Text(_) => false,
308→            Content::Blocks(blocks) => blocks.iter().any(|b| matches!(b, ContentBlock::Unknown)),
309→        }
310→    }
311→}
