  8→/// Run the `mementor enable` command.
  9→///
 10→/// 1. Create `.mementor/` directory and initialize DB with schema.
 11→/// 2. Verify embedding model loads.
 12→/// 3. Append `.mementor/` to `.gitignore` if not present.
 13→/// 4. Add mementor hooks to `.claude/settings.json`.
 14→pub fn run_enable<IN, OUT, ERR>(
 15→    runtime: &Runtime,
 16→    io: &mut dyn ConsoleIO<IN, OUT, ERR>,
 17→) -> anyhow::Result<()>
 18→where
 19→    IN: Read,
 20→    OUT: Write,
 21→    ERR: Write,
 22→{
 23→    // Guard: only allow enable from primary worktree
 24→    if runtime.context.is_linked_worktree() {
 25→        anyhow::bail!(
 26→            "mementor enable must be run from the primary worktree.\n\
 27→             Primary worktree: {}\n\
 28→             Run `mementor enable` from that directory instead.",
 29→            runtime.context.project_root().display(),
 30→        );
 31→    }
 32→
 33→    // Step 1: Create DB (open creates parent dirs + schema + vector_init)
 34→    writeln!(io.stderr(), "Initializing database...")?;
 35→    let _conn = runtime.db.open()?;
 36→    let db_path = runtime.context.db_path();
 37→    writeln!(io.stderr(), "  Database created at {}", db_path.display())?;
 38→
 39→    // Step 2: Verify embedding model loads
 40→    writeln!(io.stderr(), "Verifying embedding model...")?;
 41→    let _embedder = Embedder::new(runtime.context.model_cache_dir())?;
 42→    writeln!(io.stderr(), "  Embedding model OK")?;
 43→
 44→    // Step 3: Update .gitignore
 45→    update_gitignore(&runtime.context)?;
 46→    writeln!(io.stderr(), "  .gitignore updated")?;
 47→
 48→    // Step 4: Configure Claude Code hooks
 49→    configure_hooks(&runtime.context)?;
 50→    writeln!(io.stderr(), "  Claude Code hooks configured")?;
 51→
 52→    writeln!(io.stdout(), "mementor enabled successfully.")?;
 53→    Ok(())
 54→}
