 38→/// Strip margin markers from a multi-line string (Kotlin-style `trimMargin`).
 39→///
 40→/// Each line is scanned for the first `|` character after optional leading
 41→/// whitespace. Everything before and including the `|` is removed. Lines that
 42→/// do not contain a leading `|` are dropped.
 43→///
 44→/// Use `\|` to include a literal `|` in the output.
 45→///
 46→/// Prefer the [`trim_margin!`] macro which wraps `format!` for convenience.
 47→pub fn _trim_margin(s: &str) -> String {
 48→    s.lines()
 49→        .filter_map(|line| {
 50→            let trimmed = line.trim_start();
 51→            trimmed
 52→                .strip_prefix('|')
 53→                .map(|rest| rest.replace("\\|", "|"))
 54→        })
 55→        .collect::<Vec<_>>()
 56→        .join("\n")
 57→}
 58→
 59→/// Build a margin-trimmed string with `format!`-style interpolation.
 60→///
 61→/// Each line must start with optional whitespace followed by `|`. The `|` and
 62→/// all preceding whitespace are stripped. Use `\|` for a literal pipe character.
 63→///
 64→/// # Example
 65→///
 66→/// ```ignore
 67→/// let name = "world";
 68→/// let s = trim_margin!(
 69→///     "|Hello, {name}!
 70→///      |  indented line
 71→///      |done
 72→///      |"
 73→/// );
 74→/// assert_eq!(s, "Hello, world!\n  indented line\ndone\n");
 75→/// ```
 76→macro_rules! trim_margin {
 77→    ($fmt:literal $(, $arg:expr)* $(,)?) => {
 78→        $crate::test_util::_trim_margin(&format!($fmt $(, $arg)*))
 79→    };
 80→}
 81→pub(crate) use trim_margin;
 82→
