 13→/// Initialize file-based JSONL logging if the context has a log directory.
 14→///
 15→/// When `ctx.log_dir()` is `None`, this is a no-op.
 16→/// All errors during initialization are silently ignored so that logging
 17→/// failures never prevent mementor from functioning.
 18→pub fn init_file_logging(ctx: &MementorContext) {
 19→    let Some(log_dir) = ctx.log_dir() else {
 20→        return;
 21→    };
 22→    let _ = try_init_file_logging(log_dir, ctx.project_root());
 23→}
 24→
 25→fn try_init_file_logging(log_dir: &Path, project_root: &Path) -> anyhow::Result<()> {
 26→    let (dirname, digest) = log_subdir_parts(project_root);
 27→    let subdir_name = format!("{dirname}-{digest}");
 28→    let log_subdir = log_dir.join(&subdir_name);
 29→    fs::create_dir_all(&log_subdir)?;
 30→
 31→    let today = jiff::Zoned::now().date();
 32→    let filename = format!("{today}.jsonl");
 33→    let file_path = log_subdir.join(&filename);
 34→
 35→    let file = OpenOptions::new()
 36→        .create(true)
 37→        .append(true)
 38→        .open(file_path)?;
 39→
 40→    let filter = EnvFilter::try_from_default_env().unwrap_or_else(|_| {
 41→        EnvFilter::new("warn,mementor_lib=debug,mementor_cli=debug,mementor_main=debug")
 42→    });
 43→
 44→    tracing_subscriber::registry()
 45→        .with(filter)
 46→        .with(fmt::layer().json().with_writer(Mutex::new(file)))
 47→        .init();
 48→
 49→    cleanup_old_logs(&log_subdir, today);
 50→
 51→    Ok(())
 52→}
 53→
 54→/// Compute the subdirectory name parts from a project root path.
 55→///
 56→/// Returns `(dirname, digest)` where:
 57→/// - `dirname` is the basename of the project root
 58→/// - `digest` is the first 8 hex characters of the SHA-256 of the absolute path
 59→pub fn log_subdir_parts(project_root: &Path) -> (String, String) {
 60→    let dirname = project_root.file_name().map_or_else(
 61→        || "unknown".to_string(),
 62→        |n| n.to_string_lossy().into_owned(),
 63→    );
 64→
 65→    let mut hasher = Sha256::new();
 66→    hasher.update(project_root.to_string_lossy().as_bytes());
 67→    let hash = hasher.finalize();
 68→    let digest = hash.iter().take(4).fold(String::new(), |mut acc, b| {
 69→        use std::fmt::Write;
 70→        let _ = write!(acc, "{b:02x}");
 71→        acc
 72→    });
 73→
 74→    (dirname, digest)
 75→}
