 77→/// Delete log files older than 28 days. Errors are silently ignored.
 78→fn cleanup_old_logs(log_subdir: &Path, today: jiff::civil::Date) {
 79→    let Ok(entries) = fs::read_dir(log_subdir) else {
 80→        return;
 81→    };
 82→
 83→    for entry in entries.flatten() {
 84→        let path = entry.path();
 85→        let Some(stem) = path.file_stem().and_then(|s| s.to_str()) else {
 86→            continue;
 87→        };
 88→        let Some(ext) = path.extension().and_then(|e| e.to_str()) else {
 89→            continue;
 90→        };
 91→        if ext != "jsonl" {
 92→            continue;
 93→        }
 94→        let Ok(file_date) = stem.parse::<jiff::civil::Date>() else {
 95→            continue;
 96→        };
 97→        if let Ok(span) = today.since(file_date)
 98→            && span.get_days() >= 28
 99→        {
100→            let _ = fs::remove_file(&path);

