 65→/// Maximum number of grapheme clusters for individual field values in tool
 66→/// summaries.
 67→const MAX_VALUE_GRAPHEMES: usize = 80;
 68→
 69→/// Escape double quotes in a string value for tool summary formatting.
 70→fn escape_quotes(s: &str) -> String {
 71→    s.replace('"', "\\\"")
 72→}
 73→
 74→/// Truncate a string to at most `max_graphemes` grapheme clusters, appending
 75→/// `...` if truncated.
 76→fn truncate(s: &str, max_graphemes: usize) -> String {
 77→    // Each grapheme cluster is at least 1 byte, so if the byte length fits,
 78→    // the grapheme count must also fit — skip iteration entirely.
 79→    if s.len() <= max_graphemes {
 80→        return s.to_string();
 81→    }
 82→    let mut end = s.len();
 83→    for (count, (idx, _)) in s.grapheme_indices(true).enumerate() {
 84→        if count == max_graphemes {
 85→            end = idx;
 86→            break;
 87→        }
 88→    }
 89→    if end == s.len() {
 90→        s.to_string()
 91→    } else {
 92→        format!("{}...", &s[..end])
 93→    }
 94→}
 95→
 96→/// Extract a string field from a JSON value.
 97→fn json_str<'a>(input: &'a serde_json::Value, key: &str) -> Option<&'a str> {
 98→    input.get(key)?.as_str()
 99→}
100→
101→/// Build `Name(k1="v1", k2="v2")` from pre-formatted key-value pairs.
102→fn format_kv(name: &str, pairs: &[String]) -> String {
103→    if pairs.is_empty() {
104→        name.to_string()
105→    } else {
106→        format!("{name}({})", pairs.join(", "))
107→    }
108→}
109→
110→/// Summarize a tool with a single key field (e.g., `WebFetch`, `WebSearch`).
111→fn summarize_single_field(name: &str, input: &serde_json::Value, key: &str) -> String {
112→    if let Some(val) = json_str(input, key) {
113→        format!(
114→            "{name}({key}=\"{}\")",
115→            escape_quotes(&truncate(val, MAX_VALUE_GRAPHEMES))
116→        )
117→    } else {
118→        name.to_string()
119→    }
120→}
121→
122→/// Summarize a file tool (Read, Edit, Write) invocation.
123→fn summarize_file_tool(name: &str, input: &serde_json::Value) -> String {
124→    if let Some(path) = json_str(input, "file_path") {
125→        format!("{name}({path})")
126→    } else {
127→        name.to_string()
128→    }
129→}
130→
131→/// Summarize a `NotebookEdit` invocation.
132→fn summarize_notebook_edit(input: &serde_json::Value) -> String {
133→    let mut parts = Vec::new();
134→    if let Some(p) = json_str(input, "notebook_path") {
135→        parts.push(p.to_string());
136→    }
137→    if let Some(c) = json_str(input, "cell_id") {
138→        parts.push(format!("cell_id=\"{}\"", escape_quotes(c)));
139→    }
140→    if let Some(m) = json_str(input, "edit_mode") {
141→        parts.push(format!("edit_mode=\"{m}\""));
142→    }
143→    if parts.is_empty() {
144→        "NotebookEdit".to_string()
145→    } else {
146→        format!("NotebookEdit({})", parts.join(", "))
147→    }
148→}
149→
150→/// Summarize a search tool (Grep, Glob) invocation.
151→fn summarize_search_tool(name: &str, input: &serde_json::Value) -> String {
152→    let Some(pat) = json_str(input, "pattern") else {
153→        return name.to_string();
154→    };
155→    let mut pairs = vec![format!(
156→        "pattern=\"{}\"",
157→        escape_quotes(&truncate(pat, MAX_VALUE_GRAPHEMES))
158→    )];
159→    if let Some(p) = json_str(input, "path") {
160→        pairs.push(format!("path=\"{}\"", escape_quotes(p)));
161→    }
162→    format_kv(name, &pairs)
163→}
164→
165→/// Summarize a `Bash` invocation.
166→fn summarize_bash(input: &serde_json::Value) -> String {
167→    let mut pairs = Vec::new();
168→    if let Some(d) = json_str(input, "description") {
169→        pairs.push(format!(
170→            "desc=\"{}\"",
171→            escape_quotes(&truncate(d, MAX_VALUE_GRAPHEMES))
172→        ));
173→    }
174→    if let Some(c) = json_str(input, "command") {
175→        let first_line = c.lines().next().unwrap_or(c);
176→        pairs.push(format!(
177→            "cmd=\"{}\"",
178→            escape_quotes(&truncate(first_line, MAX_VALUE_GRAPHEMES))
179→        ));
180→    }
181→    format_kv("Bash", &pairs)
182→}
183→
184→/// Summarize a `Task` invocation.
185→fn summarize_task(input: &serde_json::Value) -> String {
186→    let mut pairs = Vec::new();
187→    if let Some(d) = json_str(input, "description") {
188→        pairs.push(format!(
189→            "desc=\"{}\"",
190→            escape_quotes(&truncate(d, MAX_VALUE_GRAPHEMES))
191→        ));
192→    }
193→    if let Some(p) = json_str(input, "prompt") {
194→        let first_line = p.lines().next().unwrap_or(p);
195→        pairs.push(format!(
196→            "prompt=\"{}\"",
197→            escape_quotes(&truncate(first_line, MAX_VALUE_GRAPHEMES))
198→        ));
199→    }
200→    format_kv("Task", &pairs)
201→}
202→
203→/// Summarize a `Skill` invocation.
204→fn summarize_skill(input: &serde_json::Value) -> String {
205→    let mut pairs = Vec::new();
206→    if let Some(s) = json_str(input, "skill") {
207→        pairs.push(format!("skill=\"{}\"", escape_quotes(s)));
208→    }
209→    if let Some(a) = json_str(input, "args") {
210→        pairs.push(format!(
211→            "args=\"{}\"",
212→            escape_quotes(&truncate(a, MAX_VALUE_GRAPHEMES))
213→        ));
214→    }
215→    format_kv("Skill", &pairs)
216→}
217→
218→/// Returns `true` if the tool carries no useful search signal and should be
219→/// excluded from tool summaries.
220→fn is_skipped_tool(name: &str) -> bool {
221→    matches!(
222→        name,
223→        "AskUserQuestion"
224→            | "EnterPlanMode"
225→            | "ExitPlanMode"
226→            | "TaskCreate"
227→            | "TaskGet"
228→            | "TaskUpdate"
229→            | "TaskList"
230→            | "TaskOutput"
231→            | "TaskStop"
232→            | "TodoWrite"
233→    )
234→}
235→
236→/// Produce a compact summary of a tool invocation.
237→fn summarize_tool(name: &str, input: Option<&serde_json::Value>) -> String {
238→    if is_skipped_tool(name) {
239→        return String::new();
240→    }
241→
242→    let Some(input) = input else {
243→        return name.to_string();
244→    };
245→
246→    match name {
247→        "Read" | "Edit" | "Write" => summarize_file_tool(name, input),
248→        "NotebookEdit" => summarize_notebook_edit(input),
249→        "Grep" | "Glob" => summarize_search_tool(name, input),
250→        "Bash" => summarize_bash(input),
251→        "Task" => summarize_task(input),
252→        "Skill" => summarize_skill(input),
253→        "WebFetch" => summarize_single_field("WebFetch", input, "url"),
254→        "WebSearch" => summarize_single_field("WebSearch", input, "query"),
255→        // Unrecognized tool: just the name
256→        _ => name.to_string(),
257→    }
258→}
