 32→pub struct RawEntry {
 33→    /// 0-based line index in the JSONL file.
 34→    pub line_index: usize,
 35→    /// Entry type (e.g., `user`, `assistant`, `summary`, `file_history_snapshot`).
 36→    pub entry_type: String,
 37→    /// Text content of the entry.
 38→    pub content: String,
 39→    /// Tool summary string (pipe-separated, e.g., "Read(src/main.rs) | Edit(ci.yml)").
 40→    pub tool_summary: String,
 41→    /// Timestamp from the transcript entry.
 42→    pub timestamp: Option<String>,
 43→}
 44→
 45→/// A PR link extracted from a transcript entry.
 46→#[derive(Debug, PartialEq)]
 47→pub struct PrLinkEntry {
 48→    pub line_index: usize,
 49→    pub session_id: String,
 50→    pub pr_number: u32,
 51→    pub pr_url: String,
 52→    pub pr_repository: String,
 53→    pub timestamp: String,
 54→}
