  9→/// A turn groups consecutive messages for semantic coherence:
 10→/// Turn[n] = User[n] + Assistant[n] + User[n+1]
 11→#[derive(Debug, PartialEq)]
 12→pub struct Turn {
 13→    /// JSONL line index of the first message in this turn (User[n]).
 14→    pub start_line: usize,
 15→    /// JSONL line index of the last owned message (Assistant[n]).
 16→    pub end_line: usize,
 17→    /// Whether this turn is provisional (missing User[n+1]).
 18→    pub provisional: bool,
 19→    /// Combined text content of the turn.
 20→    pub full_text: String,
 21→    /// Tool summaries from the assistant message (e.g., `["Read(src/main.rs)", "Edit(src/lib.rs)"]`).
 22→    pub tool_summary: Vec<String>,
 23→    /// Whether this turn's user message is a compaction summary.
 24→    pub is_compaction_summary: bool,
 25→}
 26→
 27→/// Group parsed messages into turns.
 28→/// A turn = [User[n] + Assistant[n] + User[n+1]].
 29→/// The last turn is provisional if there's no following User message.
 30→pub fn group_into_turns(messages: &[ParsedMessage]) -> Vec<Turn> {
 31→    // Collect user-assistant pairs
 32→    let mut pairs: Vec<(usize, &ParsedMessage, &ParsedMessage)> = Vec::new();
 33→    let mut i = 0;
 34→
 35→    while i < messages.len() {
 36→        if messages[i].is_user() && i + 1 < messages.len() && messages[i + 1].is_assistant() {
 37→            pairs.push((i, &messages[i], &messages[i + 1]));
 38→            i += 2;
 39→        } else {
 40→            i += 1;
 41→        }
 42→    }
 43→
 44→    if pairs.is_empty() {
 45→        return Vec::new();
 46→    }
 47→
 48→    let mut turns = Vec::new();
 49→
 50→    for (idx, (_, user, assistant)) in pairs.iter().enumerate() {
 51→        let mut full_text = format!("[User] {}\n\n[Assistant] {}", user.text, assistant.text);
 52→
 53→        let tool_summary = match &assistant.role {
 54→            MessageRole::Assistant { tool_summary } => tool_summary.clone(),
 55→            MessageRole::User => vec![],
 56→        };
 57→
 58→        if !tool_summary.is_empty() {
 59→            write!(&mut full_text, "\n\n[Tools] {}", tool_summary.join(" | ")).unwrap();
 60→        }
 61→
 62→        let mut provisional = true;
 63→
 64→        // If there's a next pair, its user message is our forward context
 65→        if idx + 1 < pairs.len() {
 66→            let (_, next_user, _) = &pairs[idx + 1];
 67→            write!(&mut full_text, "\n\n[User] {}", next_user.text).unwrap();
 68→            provisional = false;
 69→        }
 70→
 71→        turns.push(Turn {
 72→            start_line: user.line_index,
 73→            end_line: assistant.line_index,
 74→            provisional,
 75→            full_text,
 76→            tool_summary,
 77→            is_compaction_summary: user.is_compaction_summary,
 78→        });
 79→    }
 80→
 81→    turns
 82→}
 83→
 84→/// A chunk ready for embedding.
 85→#[derive(Debug)]
 86→pub struct Chunk {
 87→    /// Sequential chunk index within the turn (0-based).
 88→    pub chunk_index: usize,
 89→    /// The text content of this chunk.
 90→    pub text: String,
 91→}
 92→
 93→/// Split a turn's text into sub-chunks with overlap.
 94→pub fn chunk_turn(turn: &Turn, tokenizer: &Tokenizer) -> Vec<Chunk> {
 95→    let splitter =
 96→        MarkdownSplitter::new(ChunkConfig::new(CHUNK_TARGET_TOKENS).with_sizer(tokenizer));
 97→    let raw_chunks: Vec<&str> = splitter.chunks(&turn.full_text).collect();
 98→
 99→    if raw_chunks.is_empty() {
100→        return Vec::new();
101→    }
102→
103→    if raw_chunks.len() == 1 {
104→        return vec![Chunk {
105→            chunk_index: 0,
106→            text: raw_chunks[0].to_string(),
107→        }];
108→    }
109→
110→    // Apply overlap: prepend last N tokens from previous chunk
111→    let mut chunks = vec![Chunk {
112→        chunk_index: 0,
113→        text: raw_chunks[0].to_string(),
114→    }];
115→
116→    for (i, &chunk_text) in raw_chunks.iter().enumerate().skip(1) {
117→        let overlap_prefix =
118→            extract_tail_tokens(raw_chunks[i - 1], tokenizer, CHUNK_OVERLAP_TOKENS);
119→        let text = if overlap_prefix.is_empty() {
120→            chunk_text.to_string()
121→        } else {
122→            format!("{overlap_prefix}\n\n{chunk_text}")
123→        };
124→
125→        chunks.push(Chunk {
126→            chunk_index: i,
127→            text,
128→        });
129→    }
130→
131→    chunks
132→}
133→
134→/// Extract the last `n_tokens` worth of text from the end of `text`.
135→fn extract_tail_tokens(text: &str, tokenizer: &Tokenizer, n_tokens: usize) -> String {
136→    let Ok(encoding) = tokenizer.encode(text, false) else {
137→        return String::new();
138→    };
139→
140→    let tokens = encoding.get_ids();
141→    if tokens.is_empty() {
142→        return String::new();
143→    }
144→
145→    let start = tokens.len().saturating_sub(n_tokens);
146→    let tail_ids = &tokens[start..];
147→
148→    tokenizer.decode(tail_ids, true).unwrap_or_default()
149→}
