  1→use anyhow::Context;
  2→use rusqlite::Connection;
  3→
  4→/// The latest schema version, tracked via `SQLite`'s `user_version` pragma.
  5→const LATEST_VERSION: i32 = 2;
  6→
  7→/// Load a migration DDL file from `ddl/migrations/`.
  8→macro_rules! migration_ddl {
  9→    ($file:literal) => {
 10→        include_str!(concat!("../../ddl/migrations/", $file))
 11→    };
 12→}
 13→
 14→/// Complete DDL for the current schema. Used for fresh database installs.
 15→const SCHEMA_DDL: &str = include_str!("../../ddl/schema.sql");
 16→
 17→/// Apply schema to the database.
 18→///
 19→/// - Fresh databases (`user_version == 0`): execute the snapshot DDL directly.
 20→/// - Existing databases (`user_version < LATEST_VERSION`): apply incremental
 21→///   migrations.
 22→/// - Up-to-date databases: no-op.
 23→pub fn apply_migrations(conn: &mut Connection) -> anyhow::Result<()> {
 24→    let current: i32 = conn
 25→        .pragma_query_value(None, "user_version", |row| row.get(0))
 26→        .context("Failed to read user_version")?;
 27→
 28→    if current == 0 {
 29→        conn.execute_batch(SCHEMA_DDL)
 30→            .context("Failed to apply schema DDL")?;
 31→    } else if current < LATEST_VERSION {
 32→        apply_incremental(conn, current)?;
 33→    }
 34→
 35→    if current != LATEST_VERSION {
 36→        conn.pragma_update(None, "user_version", LATEST_VERSION)
 37→            .context("Failed to set user_version")?;
 38→    }
 39→
 40→    Ok(())
 41→}
 42→
 43→/// Apply incremental migrations from `from_version` up to `LATEST_VERSION`.
 44→fn apply_incremental(conn: &mut Connection, from: i32) -> anyhow::Result<()> {
 45→    if from < 2 {
 46→        conn.execute_batch(migration_ddl!("00002__schema_redesign.sql"))
 47→            .context("Failed to apply migration 00002 (schema redesign)")?;
 48→    }
 49→    Ok(())
 50→}
