        let mut io = BufferedIO::new();
        writeln!(io.stdout(), "hello").unwrap();
        assert_eq!(io.stdout_to_string(), "hello\n");
    }

    #[test]
    fn buffered_io_captures_stderr() {
        let mut io = BufferedIO::new();
        writeln!(io.stderr(), "error").unwrap();
        assert_eq!(io.stderr_to_string(), "error\n");
    }

    #[test]
