236→/// Get all PR links for a session, ordered by `pr_number` ascending.
237→pub fn get_pr_links_for_session(
238→    conn: &Connection,
239→    session_id: &str,
240→) -> anyhow::Result<Vec<PrLink>> {
241→    let mut stmt = conn
