168→        assert_eq!(dup.unwrap(), 0);
169→
170→        // turns UNIQUE(session_id, start_line)
171→        conn.execute(
172→            "INSERT INTO turns (session_id, start_line, end_line, full_text) \
173→             VALUES ('s1', 0, 1, 'turn text')",
174→            [],
175→        )
176→        .unwrap();
177→
178→        let dup_turn = conn.execute(
179→            "INSERT OR IGNORE INTO turns (session_id, start_line, end_line, full_text) \
180→             VALUES ('s1', 0, 1, 'different text')",
181→            [],
182→        );
183→        assert_eq!(dup_turn.unwrap(), 0);
184→
185→        // CASCADE: deleting a session cascades to entries, turns, pr_links
186→        conn.execute("DELETE FROM sessions WHERE session_id = 's1'", [])
187→            .unwrap();
188→
189→        let entry_count: i64 = conn
190→            .query_row("SELECT count(*) FROM entries", [], |row| row.get(0))
191→            .unwrap();
192→        assert_eq!(entry_count, 0);
193→
194→        let turn_count: i64 = conn
195→            .query_row("SELECT count(*) FROM turns", [], |row| row.get(0))
196→            .unwrap();
197→        assert_eq!(turn_count, 0);
198→
199→        let pr_count: i64 = conn
200→            .query_row("SELECT count(*) FROM pr_links", [], |row| row.get(0))
201→            .unwrap();
202→        assert_eq!(pr_count, 0);
203→    }
204→}
