 22→/// Normalize a file path to a relative path from the project root.
 23→///
 24→/// Tries stripping `project_dir` (current worktree CWD) or `project_root`
 25→/// (primary worktree root). If the path is already relative, returns it as-is.
 26→/// Returns `None` for absolute paths outside both directories.
 27→fn normalize_path<'a>(
 28→    path: &'a str,
 29→    project_dir: &str,
 30→    project_root: &str,
 31→) -> Option<Cow<'a, str>> {
 32→    if !path.starts_with('/') {
 33→        // Already relative — keep as-is
 34→        return Some(Cow::Borrowed(path));
 35→    }
 36→
 37→    // Try stripping project_dir first (current worktree), then project_root (primary)
 38→    for prefix in [project_dir, project_root] {
 39→        let prefix = prefix.strip_suffix('/').unwrap_or(prefix);
 40→        if let Some(rel) = path.strip_prefix(prefix) {
 41→            let rel = rel.strip_prefix('/').unwrap_or(rel);
 42→            if rel.is_empty() {
 43→                return None;
 44→            }
 45→            return Some(Cow::Owned(rel.to_string()));
 46→        }
 47→    }
 48→
 49→    // Absolute path outside the project
 50→    None
 51→}
 52→
 53→/// Known file extensions for heuristic path detection.
 54→const FILE_EXTENSIONS: &[&str] = &[
 55→    ".rs", ".ts", ".tsx", ".js", ".jsx", ".py", ".go", ".java", ".c", ".cpp", ".h", ".hpp",
 56→    ".toml", ".yaml", ".yml", ".json", ".md", ".txt", ".sh", ".sql", ".html", ".css", ".lock",
 57→    ".xml", ".cfg", ".ini", ".env", ".rb", ".swift", ".kt", ".scala",
 58→];
 59→
 60→/// Extract file paths from tool summary strings.
 61→///
 62→/// Returns `(normalized_relative_path, tool_name)` pairs. Paths outside the
 63→/// project are silently discarded.
 64→fn extract_file_paths<'a>(
 65→    tool_summaries: &'a [String],
 66→    project_dir: &str,
 67→    project_root: &str,
 68→) -> Vec<(String, &'a str)> {
 69→    let mut result = Vec::new();
 70→
 71→    for summary in tool_summaries {
 72→        // Extract tool name (text before first '(')
 73→        let Some(paren_idx) = summary.find('(') else {
 74→            continue;
 75→        };
 76→        let tool_name = &summary[..paren_idx];
 77→        let args = &summary[paren_idx + 1..summary.len().saturating_sub(1)]; // strip outer parens
 78→
 79→        match tool_name {
 80→            "Read" | "Edit" | "Write" => {
 81→                // Format: Read(/path/to/file)
 82→                if let Some(normalized) = normalize_path(args, project_dir, project_root) {
 83→                    result.push((normalized.into_owned(), tool_name));
 84→                }
 85→            }
 86→            "NotebookEdit" => {
 87→                // Format: NotebookEdit(/path, cell_id="...", edit_mode="...")
 88→                let path = args.split(',').next().unwrap_or(args).trim();
 89→                if let Some(normalized) = normalize_path(path, project_dir, project_root) {
 90→                    result.push((normalized.into_owned(), tool_name));
 91→                }
 92→            }
 93→            "Grep" => {
 94→                // Format: Grep(pattern="...", path="...")
 95→                if let Some(path) = extract_quoted_value(args, "path")
 96→                    && let Some(normalized) = normalize_path(path, project_dir, project_root)
 97→                {
 98→                    result.push((normalized.into_owned(), tool_name));
 99→                }
100→            }
101→            "Bash" => {
102→                // Format: Bash(desc="...", cmd="...")
103→                if let Some(cmd) = extract_quoted_value(args, "cmd") {
104→                    for token in extract_path_like_tokens(cmd) {
105→                        if let Some(normalized) = normalize_path(token, project_dir, project_root) {
106→                            result.push((normalized.into_owned(), tool_name));
107→                        }
108→                    }
109→                }
110→            }
111→            _ => {}
112→        }
113→    }
114→
115→    result
116→}
117→
118→/// Extract the value of a `key="value"` pair from a tool summary args string.
119→fn extract_quoted_value<'a>(args: &'a str, key: &str) -> Option<&'a str> {
120→    let needle = format!("{key}=\"");
121→    let start = args.find(&needle)? + needle.len();
122→    let remaining = &args[start..];
123→    // Find the closing quote, handling escaped quotes
124→    let mut prev_backslash = false;
125→    for (idx, ch) in remaining.char_indices() {
126→        if ch == '"' && !prev_backslash {
127→            return Some(&remaining[..idx]);
128→        }
129→        prev_backslash = ch == '\\';
130→    }
131→    None
132→}
133→
134→/// Returns `true` if a token looks like a file path or file name.
135→fn looks_like_path(token: &str) -> bool {
136→    !token.is_empty()
137→        && (token.contains('/') || FILE_EXTENSIONS.iter().any(|ext| token.ends_with(ext)))
138→}
139→
140→/// Extract path-like tokens from a command string.
141→///
142→/// Tokens are considered path-like if they contain `/` or end with a known
143→/// file extension.
144→fn extract_path_like_tokens(cmd: &str) -> Vec<&str> {
145→    cmd.split_whitespace()
146→        .map(|t| t.trim_matches(|c: char| c == '\'' || c == '"' || c == '`'))
147→        .filter(|t| looks_like_path(t))
148→        .collect()
149→}
150→
151→/// Extract `@`-mentioned file paths from turn text.
152→///
153→/// Users reference files with `@/absolute/path` syntax in prompts. This
154→/// function finds those mentions and normalizes them.
155→fn extract_at_mentions(turn_text: &str, project_dir: &str, project_root: &str) -> Vec<String> {
156→    let mut result = Vec::new();
157→    for token in turn_text.split_whitespace() {
158→        if let Some(path) = token.strip_prefix('@') {
159→            // Strip trailing punctuation that might cling to the mention
160→            let path = path.trim_end_matches(|c: char| {
161→                c == ',' || c == ';' || c == ':' || c == ')' || c == '?' || c == '!'
162→            });
163→            if path.is_empty() {
164→                continue;
165→            }
166→            if let Some(normalized) = normalize_path(path, project_dir, project_root) {
167→                result.push(normalized.into_owned());
168→            }
169→        }
170→    }
171→    result.sort();
172→    result.dedup();
173→    result
174→}
