176→/// Run the incremental ingest pipeline for a single session.
177→///
178→/// 1. Read new messages from the transcript starting at `last_line_index`.
179→/// 2. Insert raw entries into the `entries` table.
180→/// 3. If a provisional turn exists, delete it (CASCADE handles chunks + `file_mentions`).
181→/// 4. Process all turns: chunk -> embed -> store (turn + chunks + `file_mentions`).
182→/// 5. Update session state.
183→#[allow(clippy::too_many_lines)]
184→pub fn run_ingest(
185→    conn: &mut Connection,
186→    embedder: &mut Embedder,
187→    session_id: &str,
188→    transcript_path: &Path,
189→    project_dir: &str,
190→    project_root: &str,
191→) -> anyhow::Result<()> {
192→    let tokenizer = embedder.tokenizer().clone();
193→    // Load or create session
194→    let session = queries::get_session(conn, session_id)?;
195→    let (start_line, provisional_start) = if let Some(s) = &session {
196→        debug!(
197→            session_id = %session_id,
198→            last_line_index = s.last_line_index,
199→            provisional_turn_start = ?s.provisional_turn_start,
200→            last_compact_line_index = ?s.last_compact_line_index,
201→            "Loaded existing session"
202→        );
203→        (s.last_line_index, s.provisional_turn_start)
204→    } else {
205→        debug!(session_id = %session_id, "Creating new session");
206→        (0, None)
207→    };
208→
209→    // Parse new messages from the transcript starting at start_line.
210→    // If there's a provisional turn, re-read from its start to re-process it.
211→    let read_from = provisional_start.unwrap_or(start_line);
212→    let ParseResult {
213→        messages,
214→        pr_links,
215→        raw_entries,
216→    } = parse_transcript(transcript_path, read_from)?;
217→    debug!(
218→        session_id = %session_id,
219→        read_from = read_from,
220→        message_count = messages.len(),
221→        pr_link_count = pr_links.len(),
222→        raw_entry_count = raw_entries.len(),
223→        "Parsed transcript messages"
224→    );
225→    if messages.is_empty() && pr_links.is_empty() && raw_entries.is_empty() {
226→        debug!("No new data found in transcript");
227→        return Ok(());
228→    }
229→
230→    // Ensure session record exists (required for foreign keys)
231→    if session.is_none() {
232→        upsert_session(
233→            conn,
234→            &Session {
235→                session_id: session_id.to_string(),
236→                transcript_path: transcript_path.to_string_lossy().to_string(),
237→                project_dir: project_dir.to_string(),
238→                started_at: None,
239→                last_line_index: read_from,
240→                provisional_turn_start: None,
241→                last_compact_line_index: None,
242→            },
243→        )?;
244→    }
245→
246→    // Insert raw entries into the entries table (INSERT OR IGNORE for idempotency)
247→    for entry in &raw_entries {
248→        insert_entry(
249→            conn,
250→            session_id,
251→            entry.line_index,
252→            &entry.entry_type,
253→            &entry.content,
254→            &entry.tool_summary,
255→            entry.timestamp.as_deref(),
256→        )?;
257→    }
258→    if !raw_entries.is_empty() {
259→        debug!(
260→            session_id = %session_id,
261→            count = raw_entries.len(),
262→            "Inserted raw entries"
263→        );
264→    }
265→
266→    // Insert PR links (idempotent via INSERT OR IGNORE)
267→    for pr_link in &pr_links {
268→        insert_pr_link(
269→            conn,
270→            session_id,
271→            pr_link.pr_number,
272→            &pr_link.pr_url,
273→            &pr_link.pr_repository,
274→            &pr_link.timestamp,
275→        )?;
276→    }
277→    if !pr_links.is_empty() {
278→        debug!(
279→            session_id = %session_id,
280→            count = pr_links.len(),
281→            "Inserted PR links"
282→        );
283→    }
284→
285→    // Group messages into turns
286→    let turns = group_into_turns(&messages);
287→    debug!(
288→        session_id = %session_id,
289→        turn_count = turns.len(),
290→        "Grouped messages into turns"
291→    );
292→    for turn in &turns {
293→        debug!(
294→            start_line = turn.start_line,
295→            end_line = turn.end_line,
296→            provisional = turn.provisional,
297→            text_len = turn.full_text.len(),
298→            "Turn detail"
299→        );
300→    }
301→
302→    if turns.is_empty() {
303→        debug!("No turns formed from messages");
304→        // Still update session to advance past raw entries / PR links
305→        let last_line = raw_entries
306→            .iter()
307→            .map(|e| e.line_index)
308→            .chain(pr_links.iter().map(|p| p.line_index))
309→            .max()
310→            .map_or(read_from, |m| m + 1);
311→        upsert_session(
312→            conn,
313→            &Session {
314→                session_id: session_id.to_string(),
315→                transcript_path: transcript_path.to_string_lossy().to_string(),
316→                project_dir: project_dir.to_string(),
317→                started_at: None,
318→                last_line_index: last_line,
319→                provisional_turn_start: None,
320→                last_compact_line_index: session.and_then(|s| s.last_compact_line_index),
321→            },
322→        )?;
323→        return Ok(());
324→    }
325→
326→    // If a provisional turn existed, delete it (CASCADE cleans chunks + file_mentions)
327→    if let Some(prov_line) = provisional_start {
328→        let deleted = delete_turn_at(conn, session_id, prov_line)?;
329→        debug!("Deleted {deleted} provisional turn at start_line={prov_line}");
330→    }
331→
332→    // Process each turn: chunk -> embed -> store
333→    let mut last_line_index = read_from;
334→    let mut new_provisional_start: Option<usize> = None;
335→
336→    for turn in &turns {
337→        let chunks = chunk_turn(turn, &tokenizer);
338→        debug!(
339→            session_id = %session_id,
340→            start_line = turn.start_line,
341→            chunk_count = chunks.len(),
342→            provisional = turn.provisional,
343→            "Chunked turn"
344→        );
345→        if chunks.is_empty() {
346→            continue;
347→        }
348→
349→        // Embed all chunks OUTSIDE the transaction (avoid holding write lock during inference)
350→        let texts: Vec<&str> = chunks.iter().map(|c| c.text.as_str()).collect();
351→        let embeddings = embedder.embed_batch(&texts).with_context(|| {
352→            format!(
353→                "Failed to embed chunks for turn at line {}",
354→                turn.start_line
355→            )
356→        })?;
357→
358→        // Transaction: upsert turn + insert chunks + insert file mentions
359→        let tx = conn.transaction()?;
360→
361→        let turn_id = upsert_turn(
362→            &tx,
363→            session_id,
364→            turn.start_line,
365→            turn.end_line,
366→            turn.provisional,
367→            &turn.full_text,
368→        )?;
369→
370→        for (chunk, embedding) in chunks.iter().zip(embeddings.iter()) {
371→            insert_chunk(&tx, turn_id, chunk.chunk_index, embedding)?;
372→        }
373→
374→        // Extract and store file mentions from tool summaries
375→        let file_paths = extract_file_paths(&turn.tool_summary, project_dir, project_root);
376→        for (file_path, tool_name) in &file_paths {
377→            insert_file_mention(&tx, turn_id, file_path, tool_name)?;
378→        }
379→
380→        // Extract and store @-mentioned file paths from user text
381→        let at_mentions = extract_at_mentions(&turn.full_text, project_dir, project_root);
382→        for file_path in &at_mentions {
383→            insert_file_mention(&tx, turn_id, file_path, "mention")?;
384→        }
385→
386→        tx.commit()?;
387→
388→        if !file_paths.is_empty() || !at_mentions.is_empty() {
389→            debug!(
390→                session_id = %session_id,
391→                start_line = turn.start_line,
392→                tool_files = file_paths.len(),
393→                at_mentions = at_mentions.len(),
394→                "Stored file mentions"
395→            );
396→        }
397→
398→        if turn.provisional {
399→            new_provisional_start = Some(turn.start_line);
400→        }
401→
402→        // Update last_line_index to be beyond all messages in this turn
403→        last_line_index = turn.end_line + 1;
404→    }
405→
406→    // Messages are guaranteed non-empty: turns require at least one user-assistant pair.
407→    let max_message_line = messages.iter().map(|m| m.line_index).max().unwrap();
408→    last_line_index = last_line_index.max(max_message_line + 1);
409→
410→    // Upsert session state
411→    upsert_session(
412→        conn,
413→        &Session {
414→            session_id: session_id.to_string(),
415→            transcript_path: transcript_path.to_string_lossy().to_string(),
416→            project_dir: project_dir.to_string(),
417→            started_at: None,
418→            last_line_index,
419→            provisional_turn_start: new_provisional_start,
420→            last_compact_line_index: session.and_then(|s| s.last_compact_line_index),
421→        },
422→    )?;
423→
424→    let total = turns.len();
425→    let provisional = usize::from(new_provisional_start.is_some());
426→    let complete = total - provisional;
427→    info!(
428→        "Ingested {total} turns ({complete} complete, {provisional} provisional) for session {session_id}"
429→    );
430→
431→    Ok(())
432→}
