  9→
 10→/// Role-specific data for a parsed message.
 11→#[derive(Debug, Default, PartialEq)]
 12→pub enum MessageRole {
 13→    #[default]
 14→    User,
 15→    Assistant {
 16→        tool_summary: Vec<String>,
 17→    },
 18→}
 19→
 20→/// Parsed transcript messages with their line indices.
 21→#[derive(Debug, Default)]
 22→pub struct ParsedMessage {
 23→    /// 0-based line index in the JSONL file.
 24→    pub line_index: usize,
 25→    /// Extracted text content (`tool_use`/`tool_result` blocks stripped).
 26→    pub text: String,
 27→    /// Role and role-specific data.
 28→    pub role: MessageRole,
 29→    /// Whether this message is a compaction summary (post-compaction context).
 30→    pub is_compaction_summary: bool,
 31→}
 32→
 33→/// A raw entry extracted from the transcript for storage in the `entries` table.
 34→#[derive(Debug, Default, PartialEq)]
 35→pub struct RawEntry {
 36→    /// 0-based line index in the JSONL file.
 37→    pub line_index: usize,
 38→    /// Entry type (e.g., `user`, `assistant`, `summary`, `file_history_snapshot`).
 39→    pub entry_type: String,
 40→    /// Text content of the entry.
 41→    pub content: String,
 42→    /// Tool summary string (pipe-separated, e.g., "Read(src/main.rs) | Edit(ci.yml)").
 43→    pub tool_summary: String,
 44→    /// Timestamp from the transcript entry.
 45→    pub timestamp: Option<String>,
 46→}
 47→
 48→/// A PR link extracted from a transcript entry.
 49→#[derive(Debug, Default, PartialEq)]
 50→pub struct PrLinkEntry {
 51→    pub line_index: usize,
 52→    pub session_id: String,
 53→    pub pr_number: u32,
 54→    pub pr_url: String,
 55→    pub pr_repository: String,
 56→    pub timestamp: String,
 57→}
 58→
 59→/// Result of parsing a transcript file.
 60→#[derive(Debug, Default)]
 61→pub struct ParseResult {
 62→    pub messages: Vec<ParsedMessage>,
 63→    pub pr_links: Vec<PrLinkEntry>,
 64→    pub raw_entries: Vec<RawEntry>,
 65→}
 66→
 67→impl ParsedMessage {
 68→    pub fn is_user(&self) -> bool {
 69→        matches!(self.role, MessageRole::User)
 70→    }
 71→
 72→    pub fn is_assistant(&self) -> bool {
 73→        matches!(self.role, MessageRole::Assistant { .. })
 74→    }
 75→}
 76→
 77→/// Entry types that are noise and should be skipped entirely.
 78→fn is_noise_type(entry_type: &str) -> bool {
 79→    matches!(
 80→        entry_type,
 81→        "progress" | "queue-operation" | "turn_duration" | "stop_hook_summary"
 82→    )
 83→}
 84→
 85→/// Outcome of processing a single transcript entry.
 86→enum EntryAction {
 87→    /// Push a PR link.
 88→    PrLink(PrLinkEntry),
 89→    /// Push a raw entry only (no parsed message).
 90→    RawOnly(RawEntry),
 91→    /// Push both a raw entry and a parsed message.
 92→    RawAndMessage(RawEntry, ParsedMessage),
 93→    /// Skip this line entirely.
 94→    Skip,
 95→}
 96→
 97→/// Classify and extract data from a single transcript entry.
 98→fn process_entry(line_idx: usize, entry: TranscriptEntry, line: &str) -> EntryAction {
 99→    let entry_type = entry.entry_type.as_deref().unwrap_or("");
100→
101→    if entry_type == "pr-link" {
102→        if let Some(sid) = entry.session_id.as_ref()
103→            && let Some(pr_number) = entry.pr_number
104→            && let Some(pr_url) = entry.pr_url.as_ref()
105→            && let Some(pr_repo) = entry.pr_repository.as_ref()
106→            && let Some(ts) = entry.timestamp.as_ref()
107→        {
108→            return EntryAction::PrLink(PrLinkEntry {
109→                line_index: line_idx,
110→                session_id: sid.clone(),
111→                pr_number,
112→                pr_url: pr_url.clone(),
113→                pr_repository: pr_repo.clone(),
114→                timestamp: ts.clone(),
115→            });
116→        }
117→        return EntryAction::Skip;
118→    }
119→
120→    if is_noise_type(entry_type) {
121→        return EntryAction::Skip;
122→    }
123→
124→    // Resolve effective entry type for the entries table.
125→    // Real transcripts use `"type": "message"` with the actual role in `message.role`,
126→    // so we defer role-based resolution for "message" type to after parsing the message.
127→    let effective_type = match entry_type {
128→        "system" if entry.sub_type.as_deref() == Some("compact_boundary") => "compact_boundary",
129→        "file-history-snapshot" => "file_history_snapshot",
130→        "user" | "assistant" | "summary" | "message" => entry_type,
131→        _ => return EntryAction::Skip,
132→    };
133→
134→    let Some(message) = entry.message else {
135→        if effective_type == "compact_boundary" || effective_type == "file_history_snapshot" {
136→            return EntryAction::RawOnly(RawEntry {
137→                line_index: line_idx,
138→                entry_type: effective_type.to_string(),
139→                content: String::new(),
140→                tool_summary: String::new(),
141→                timestamp: entry.timestamp.clone(),
142→            });
143→        }
144→        return EntryAction::Skip;
145→    };
146→
147→    // For "message" type entries, resolve the effective type from the message role.
148→    let effective_type = if effective_type == "message" {
149→        message.role.as_str()
150→    } else {
151→        effective_type
152→    };
153→
154→    if message.content.has_unknown_blocks() {
155→        debug!(line = line_idx, raw = %line, "message contains unknown content block type(s), ignoring those blocks");
156→    }
157→
158→    let role = match message.role.as_str() {
159→        "assistant" => MessageRole::Assistant {
160→            tool_summary: message.content.extract_tool_summary(),
161→        },
162→        "user" => MessageRole::User,
163→        _ => return EntryAction::Skip,
164→    };
165→
166→    let text = message.content.extract_text();
167→    let tool_summary_text = match &role {
168→        MessageRole::Assistant { tool_summary } if !tool_summary.is_empty() => {
169→            tool_summary.join(" | ")
170→        }
171→        _ => String::new(),
172→    };
173→
174→    let raw = RawEntry {
175→        line_index: line_idx,
176→        entry_type: effective_type.to_string(),
177→        content: text.clone(),
178→        tool_summary: tool_summary_text,
179→        timestamp: entry.timestamp.clone(),
180→    };
181→
182→    if text.trim().is_empty() && raw.tool_summary.is_empty() {
183→        return EntryAction::RawOnly(raw);
184→    }
185→
186→    let is_compaction_summary = matches!(&role, MessageRole::User)
187→        && text.starts_with(crate::config::COMPACTION_SUMMARY_PREFIX);
188→
189→    EntryAction::RawAndMessage(
190→        raw,
191→        ParsedMessage {
192→            line_index: line_idx,
193→            text,
194→            role,
195→            is_compaction_summary,
196→        },
197→    )
198→}
199→
200→/// Read transcript JSONL file starting from `start_line` (0-based).
201→/// Returns parsed messages with user/assistant text content, plus any PR link
202→/// entries found in the transcript, plus raw entries for the `entries` table.
203→pub fn parse_transcript(path: &Path, start_line: usize) -> anyhow::Result<ParseResult> {
204→    let file = File::open(path)
205→        .with_context(|| format!("Failed to open transcript: {}", path.display()))?;
206→    let reader = BufReader::new(file);
207→    let mut messages = Vec::new();
208→    let mut pr_links = Vec::new();
209→    let mut raw_entries = Vec::new();
210→
211→    for (line_idx, line_result) in reader.lines().enumerate() {
212→        if line_idx < start_line {
213→            continue;
214→        }
215→
216→        let line = match line_result {
217→            Ok(l) => l,
218→            Err(e) => {
219→                warn!(line = line_idx, error = %e, "Failed to read line, skipping");
220→                continue;
221→            }
222→        };
223→
224→        if line.trim().is_empty() {
225→            continue;
226→        }
227→
228→        let entry: TranscriptEntry = match serde_json::from_str(&line) {
229→            Ok(e) => e,
230→            Err(e) => {
231→                warn!(line = line_idx, error = %e, "Failed to parse JSON line, skipping");
232→                continue;
233→            }
234→        };
235→
236→        match process_entry(line_idx, entry, &line) {
237→            EntryAction::PrLink(pr) => pr_links.push(pr),
238→            EntryAction::RawOnly(raw) => raw_entries.push(raw),
239→            EntryAction::RawAndMessage(raw, msg) => {
240→                raw_entries.push(raw);
241→                messages.push(msg);
242→            }
243→            EntryAction::Skip => {}
244→        }
245→    }
246→
247→    Ok(ParseResult {
248→        messages,
249→        pr_links,
250→        raw_entries,
251→    })
252→}
