  3→/// Abstracts stdin/stdout/stderr for dependency injection and testability.
  4→pub trait ConsoleIO<IN: Read, OUT: Write, ERR: Write> {
  5→    fn stdin(&mut self) -> &mut IN;
  6→    fn stdout(&mut self) -> &mut OUT;
  7→    fn stderr(&mut self) -> &mut ERR;
  8→}
  9→
 10→/// Real implementation that uses actual stdin/stdout/stderr.
 11→pub struct StdIO {
 12→    stdin: Stdin,
 13→    stdout: Stdout,
 14→    stderr: Stderr,
 15→}
 16→
 17→impl StdIO {
 18→    #[must_use]
 19→    pub fn new() -> Self {
 20→        Self::default()
 21→    }
 22→}
 23→
 24→impl Default for StdIO {
 25→    fn default() -> Self {
 26→        Self {
 27→            stdin: std::io::stdin(),
 28→            stdout: std::io::stdout(),
 29→            stderr: std::io::stderr(),
 30→        }
 31→    }
 32→}
 33→
 34→impl ConsoleIO<Stdin, Stdout, Stderr> for StdIO {
 35→    fn stdin(&mut self) -> &mut Stdin {
 36→        &mut self.stdin
 37→    }
 38→
 39→    fn stdout(&mut self) -> &mut Stdout {
 40→        &mut self.stdout
 41→    }
 42→
 43→    fn stderr(&mut self) -> &mut Stderr {
 44→        &mut self.stderr
 45→    }
 46→}
 47→
 48→/// Test implementation that captures output and provides canned stdin.
 49→#[derive(Default)]
 50→pub struct BufferedIO {
 51→    stdin: Cursor<Vec<u8>>,
 52→    stdout: Vec<u8>,
 53→    stderr: Vec<u8>,
 54→}
 55→
 56→impl BufferedIO {
 57→    #[must_use]
 58→    pub fn new() -> Self {
 59→        Self::default()
 60→    }
 61→
 62→    /// Create a `BufferedIO` with pre-filled stdin data.
 63→    #[must_use]
 64→    pub fn with_stdin(data: &[u8]) -> Self {
 65→        Self {
 66→            stdin: Cursor::new(data.to_vec()),
 67→            ..Self::default()
 68→        }
 69→    }
 70→
 71→    /// Returns the captured stdout content as a string.
 72→    pub fn stdout_to_string(&self) -> String {
 73→        String::from_utf8_lossy(&self.stdout).into_owned()
 74→    }
 75→
 76→    /// Returns the captured stderr content as a string.
 77→    pub fn stderr_to_string(&self) -> String {
 78→        String::from_utf8_lossy(&self.stderr).into_owned()
 79→    }
 80→}
 81→
 82→impl ConsoleIO<Cursor<Vec<u8>>, Vec<u8>, Vec<u8>> for BufferedIO {
 83→    fn stdin(&mut self) -> &mut Cursor<Vec<u8>> {
 84→        &mut self.stdin
 85→    }
 86→
 87→    fn stdout(&mut self) -> &mut Vec<u8> {
 88→        &mut self.stdout
 89→    }
 90→
 91→    fn stderr(&mut self) -> &mut Vec<u8> {
 92→        &mut self.stderr
 93→    }
 94→}
