  1→use std::io::{Read, Write};
  2→
  3→use mementor_lib::context::MementorContext;
  4→use mementor_lib::embedding::embedder::Embedder;
  5→use mementor_lib::output::ConsoleIO;
  6→use mementor_lib::runtime::Runtime;
  7→
  8→/// Run the `mementor enable` command.
  9→///
 10→/// 1. Create `.mementor/` directory and initialize DB with schema.
 11→/// 2. Verify embedding model loads.
 12→/// 3. Append `.mementor/` to `.gitignore` if not present.
 13→/// 4. Add mementor hooks to `.claude/settings.json`.
 14→pub fn run_enable<IN, OUT, ERR>(
 15→    runtime: &Runtime,
 16→    io: &mut dyn ConsoleIO<IN, OUT, ERR>,
 17→) -> anyhow::Result<()>
 18→where
 19→    IN: Read,
 20→    OUT: Write,
 21→    ERR: Write,
 22→{
 23→    // Guard: only allow enable from primary worktree
 24→    if runtime.context.is_linked_worktree() {
 25→        anyhow::bail!(
 26→            "mementor enable must be run from the primary worktree.\n\
 27→             Primary worktree: {}\n\
 28→             Run `mementor enable` from that directory instead.",
 29→            runtime.context.project_root().display(),
 30→        );
 31→    }
 32→
 33→    // Step 1: Create DB (open creates parent dirs + schema + vector_init)
 34→    writeln!(io.stderr(), "Initializing database...")?;
 35→    let _conn = runtime.db.open()?;
 36→    let db_path = runtime.context.db_path();
 37→    writeln!(io.stderr(), "  Database created at {}", db_path.display())?;
 38→
 39→    // Step 2: Verify embedding model loads
 40→    writeln!(io.stderr(), "Verifying embedding model...")?;
 41→    let _embedder = Embedder::new(runtime.context.model_cache_dir())?;
 42→    writeln!(io.stderr(), "  Embedding model OK")?;
 43→
 44→    // Step 3: Update .gitignore
 45→    update_gitignore(&runtime.context)?;
 46→    writeln!(io.stderr(), "  .gitignore updated")?;
 47→
 48→    // Step 4: Configure Claude Code hooks
 49→    configure_hooks(&runtime.context)?;
 50→    writeln!(io.stderr(), "  Claude Code hooks configured")?;
 51→
 52→    writeln!(io.stdout(), "mementor enabled successfully.")?;
 53→    Ok(())
 54→}
 55→
 56→/// Append `.mementor/` to `.gitignore` if not already present.
 57→fn update_gitignore(ctx: &MementorContext) -> anyhow::Result<()> {
 58→    let gitignore_path = ctx.gitignore_path();
 59→    let entry = ".mementor/";
 60→
 61→    if gitignore_path.exists() {
 62→        let existing = std::fs::read_to_string(&gitignore_path)?;
 63→        if existing.lines().any(|line| line.trim() == entry) {
 64→            return Ok(());
 65→        }
 66→        // Append with newline separator
 67→        let separator = if existing.ends_with('\n') { "" } else { "\n" };
 68→        std::fs::write(&gitignore_path, format!("{existing}{separator}{entry}\n"))?;
 69→    } else {
 70→        std::fs::write(&gitignore_path, format!("{entry}\n"))?;
 71→    }
 72→
 73→    Ok(())
 74→}
 75→
 76→/// Add mementor hooks to `.claude/settings.json`.
 77→fn configure_hooks(ctx: &MementorContext) -> anyhow::Result<()> {
 78→    let settings_path = ctx.claude_settings_path();
 79→
 80→    // Ensure .claude/ directory exists
 81→    if let Some(parent) = settings_path.parent() {
 82→        std::fs::create_dir_all(parent)?;
 83→    }
 84→
 85→    let (mut settings, has_trailing_newline): (serde_json::Value, bool) = if settings_path.exists()
 86→    {
 87→        let raw = std::fs::read_to_string(&settings_path)?;
 88→        let trailing = raw.ends_with('\n');
 89→        (serde_json::from_str(&raw)?, trailing)
 90→    } else {
 91→        (serde_json::json!({}), true)
 92→    };
 93→
 94→    // Build hook config — only Stop and PreCompact
 95→    let stop_hook = serde_json::json!({
 96→        "hooks": [{
 97→            "type": "command",
 98→            "command": "mementor hook stop"
 99→        }]
100→    });
101→
102→    let pre_compact_hook = serde_json::json!({
103→        "hooks": [{
104→            "type": "command",
105→            "command": "mementor hook pre-compact"
106→        }]
107→    });
108→
109→    // Merge hooks into settings
110→    let hooks = settings
111→        .as_object_mut()
112→        .ok_or_else(|| anyhow::anyhow!("settings.json root is not an object"))?
113→        .entry("hooks")
114→        .or_insert_with(|| serde_json::json!({}));
115→
116→    let hooks_obj = hooks
117→        .as_object_mut()
118→        .ok_or_else(|| anyhow::anyhow!("hooks field is not an object"))?;
119→
120→    // Upsert mementor hooks (replace existing mementor entries, preserve others)
121→    upsert_hook_entry(hooks_obj, "Stop", stop_hook);
122→    upsert_hook_entry(hooks_obj, "PreCompact", pre_compact_hook);
123→
124→    // Write settings back, preserving original EOF newline behavior
125→    let mut formatted = serde_json::to_string_pretty(&settings)?;
126→    if has_trailing_newline {
127→        formatted.push('\n');
128→    }
129→    std::fs::write(&settings_path, formatted)?;
130→
131→    Ok(())
132→}
133→
134→/// Upsert a mementor hook entry into the event array.
135→///
136→/// If an entry with the exact same command already exists, it is left
137→/// untouched (preserving the original key order). Otherwise, any existing
138→/// mementor entries (commands starting with "mementor") are removed and the
139→/// new entry is appended. Non-mementor entries are always preserved.
140→fn upsert_hook_entry(
141→    hooks_obj: &mut serde_json::Map<String, serde_json::Value>,
142→    event_name: &str,
143→    hook_entry: serde_json::Value,
144→) {
145→    let arr = hooks_obj
146→        .entry(event_name)
147→        .or_insert_with(|| serde_json::json!([]));
148→
149→    if let Some(arr) = arr.as_array_mut() {
150→        let target_cmd = hook_entry["hooks"]
151→            .as_array()
152→            .and_then(|h| h.first())
153→            .and_then(|h| h["command"].as_str());
154→
155→        let already_exists = target_cmd.is_some_and(|cmd| {
156→            arr.iter().any(|entry| {
157→                entry["hooks"]
158→                    .as_array()
159→                    .is_some_and(|hooks| hooks.iter().any(|h| h["command"].as_str() == Some(cmd)))
160→            })
161→        });
162→
163→        if already_exists {
164→            return;
165→        }
166→
167→        arr.retain(|entry| {
168→            !entry["hooks"].as_array().is_some_and(|hooks| {
169→                hooks.iter().any(|h| {
170→                    h["command"]
171→                        .as_str()
172→                        .is_some_and(|cmd| cmd.starts_with("mementor"))
173→                })
174→            })
175→        });
176→
177→        arr.push(hook_entry);
178→    }
179→}
