 3→/// Input received from the Claude Code Stop hook via stdin.
 4→#[derive(Debug, Deserialize)]
 5→pub struct StopHookInput {
 6→    /// The session ID of the Claude Code conversation.
 7→    pub session_id: String,
 8→    /// Path to the JSONL transcript file.
 9→    pub transcript_path: String,
10→    /// The project working directory.
11→    pub cwd: String,
12→}
13→
14→/// Read and parse the stop hook input from stdin.
15→pub fn read_stop_input(reader: &mut dyn std::io::Read) -> anyhow::Result<StopHookInput> {
16→    let mut buf = String::new();
17→    reader.read_to_string(&mut buf)?;
18→    let input: StopHookInput = serde_json::from_str(&buf)?;
19→    Ok(input)
20→}
