13→/// Handle the `PreCompact` hook: ingest latest conversation before compaction,
14→/// then mark the compaction boundary in the session record.
15→pub fn handle_pre_compact<IN, OUT, ERR>(
16→    input: &PreCompactInput,
17→    runtime: &Runtime,
18→    io: &mut dyn ConsoleIO<IN, OUT, ERR>,
19→) -> anyhow::Result<()>
20→where
21→    IN: Read,
22→    OUT: Write,
23→    ERR: Write,
24→{
25→    debug!(
26→        hook = "PreCompact",
27→        session_id = %input.session_id,
28→        trigger = %input.trigger,
29→        custom_instructions_len = input.custom_instructions.len(),
30→        "Hook received"
31→    );
32→
33→    if !runtime.db.is_ready() {
34→        writeln!(
35→            io.stderr(),
36→            "mementor is not enabled for this project. Run `mementor enable` first."
37→        )?;
38→        return Ok(());
39→    }
40→
41→    let mut conn = runtime.db.open()?;
42→    let mut embedder = Embedder::new(runtime.context.model_cache_dir())?;
43→
44→    // Ingest latest conversation before compaction erases active context
45→    let project_root = runtime.context.project_root().to_string_lossy();
46→    run_ingest(
47→        &mut conn,
48→        &mut embedder,
49→        &input.session_id,
50→        Path::new(&input.transcript_path),
51→        &input.cwd,
52→        &project_root,
53→    )?;
54→
55→    // Mark the compaction boundary
56→    update_compact_line(&conn, &input.session_id)?;
57→
58→    debug!(
59→        hook = "PreCompact",
60→        session_id = %input.session_id,
61→        "Compaction boundary recorded"
62→    );
63→
64→    Ok(())
65→}
