 11→/// Create a [`Runtime`] with an in-memory database and a tempdir-based context.
 12→///
 13→/// The `name` must be unique per test to prevent cross-test DB collisions.
 14→/// The caller must hold the returned [`tempfile::TempDir`] to keep the
 15→/// temporary directory alive for the duration of the test.
 16→pub fn runtime_in_memory(name: &str) -> (tempfile::TempDir, Runtime) {
 17→    let tmp = tempfile::tempdir().unwrap();
 18→    // Create a bare .git directory so that the tempdir looks like a git repo.
 19→    std::fs::create_dir(tmp.path().join(".git")).unwrap();
 20→    let ctx = MementorContext::new(tmp.path().to_path_buf()).unwrap();
