}

let mut chunks = vec![Chunk {
    chunk_index: 0,
    text: raw_chunks[0].to_string(),
}];

for (i, &chunk_text) in raw_chunks.iter().enumerate().skip(1) {
    // ...
}
```
- **After**:
```rust
if raw_chunks.is_empty() {
    return Vec::new();
}

let mut chunks = vec![Chunk {
    chunk_index: 0,
    text: raw_chunks[0].to_string(),
}];

for (i, &chunk_text) in raw_chunks.iter().enumerate().skip(1) {
    // ... (same as before)
}

chunks
