 23→/// Normalize a file path to a relative path from the project root.
 24→///
 25→/// Tries stripping `project_dir` (current worktree CWD) or `project_root`
 26→/// (primary worktree root). If the path is already relative, returns it as-is.
 27→/// Returns `None` for absolute paths outside both directories.
 28→fn normalize_path<'a>(
 29→    path: &'a str,
 30→    project_dir: &str,
 31→    project_root: &str,
 32→) -> Option<Cow<'a, str>> {
 33→    if !path.starts_with('/') {
 34→        // Already relative — keep as-is
 35→        return Some(Cow::Borrowed(path));
 36→    }
 37→
 38→    // Try stripping project_dir first (current worktree), then project_root (primary)
 39→    for prefix in [project_dir, project_root] {
 40→        let prefix = prefix.strip_suffix('/').unwrap_or(prefix);
 41→        if let Some(rel) = path.strip_prefix(prefix) {
 42→            let rel = rel.strip_prefix('/').unwrap_or(rel);
 43→            if rel.is_empty() {
 44→                return None;
 45→            }
 46→            return Some(Cow::Owned(rel.to_string()));
 47→        }
 48→    }
 49→
 50→    // Absolute path outside the project
 51→    None
 52→}
 53→
 54→/// Known file extensions for heuristic path detection.
 55→const FILE_EXTENSIONS: &[&str] = &[
 56→    ".rs", ".ts", ".tsx", ".js", ".jsx", ".py", ".go", ".java", ".c", ".cpp", ".h", ".hpp",
 57→    ".toml", ".yaml", ".yml", ".json", ".md", ".txt", ".sh", ".sql", ".html", ".css", ".lock",
 58→    ".xml", ".cfg", ".ini", ".env", ".rb", ".swift", ".kt", ".scala",
 59→];
 60→
 61→/// Extract file paths from tool summary strings.
 62→///
 63→/// Returns `(normalized_relative_path, tool_name)` pairs. Paths outside the
 64→/// project are silently discarded.
 65→fn extract_file_paths<'a>(
 66→    tool_summaries: &'a [String],
 67→    project_dir: &str,
 68→    project_root: &str,
 69→) -> Vec<(String, &'a str)> {
 70→    let mut result = Vec::new();
 71→
 72→    for summary in tool_summaries {
 73→        // Extract tool name (text before first '(')
 74→        let Some(paren_idx) = summary.find('(') else {
 75→            continue;
 76→        };
 77→        let tool_name = &summary[..paren_idx];
 78→        let args = &summary[paren_idx + 1..summary.len().saturating_sub(1)]; // strip outer parens
 79→
 80→        match tool_name {
 81→            "Read" | "Edit" | "Write" => {
 82→                // Format: Read(/path/to/file)
 83→                if let Some(normalized) = normalize_path(args, project_dir, project_root) {
 84→                    result.push((normalized.into_owned(), tool_name));
 85→                }
 86→            }
 87→            "NotebookEdit" => {
 88→                // Format: NotebookEdit(/path, cell_id="...", edit_mode="...")
 89→                let path = args.split(',').next().unwrap_or(args).trim();
 90→                if let Some(normalized) = normalize_path(path, project_dir, project_root) {
 91→                    result.push((normalized.into_owned(), tool_name));
 92→                }
 93→            }
 94→            "Grep" => {
 95→                // Format: Grep(pattern="...", path="...")
 96→                if let Some(path) = extract_quoted_value(args, "path")
 97→                    && let Some(normalized) = normalize_path(path, project_dir, project_root)
 98→                {
 99→                    result.push((normalized.into_owned(), tool_name));
100→                }
101→            }
102→            "Bash" => {
103→                // Format: Bash(desc="...", cmd="...")
104→                if let Some(cmd) = extract_quoted_value(args, "cmd") {
105→                    for token in extract_path_like_tokens(cmd) {
106→                        if let Some(normalized) = normalize_path(token, project_dir, project_root) {
107→                            result.push((normalized.into_owned(), tool_name));
108→                        }
109→                    }
110→                }
111→            }
112→            _ => {}
113→        }
114→    }
115→
116→    result
117→}
