119→/// Extract the value of a `key="value"` pair from a tool summary args string.
120→fn extract_quoted_value<'a>(args: &'a str, key: &str) -> Option<&'a str> {
121→    let needle = format!("{key}=\"");
122→    let start = args.find(&needle)? + needle.len();
123→    let remaining = &args[start..];
124→    // Find the closing quote, handling escaped quotes
125→    let mut prev_backslash = false;
126→    for (idx, ch) in remaining.char_indices() {
127→        if ch == '"' && !prev_backslash {
128→            return Some(&remaining[..idx]);
129→        }
130→        prev_backslash = ch == '\\';
131→    }
132→    None
133→}
134→
135→/// Returns `true` if a token looks like a file path or file name.
136→fn looks_like_path(token: &str) -> bool {
137→    !token.is_empty()
138→        && (token.contains('/') || FILE_EXTENSIONS.iter().any(|ext| token.ends_with(ext)))
139→}
140→
141→/// Extract path-like tokens from a command string.
142→///
143→/// Tokens are considered path-like if they contain `/` or end with a known
144→/// file extension.
145→fn extract_path_like_tokens(cmd: &str) -> Vec<&str> {
146→    cmd.split_whitespace()
147→        .map(|t| t.trim_matches(|c: char| c == '\'' || c == '"' || c == '`'))
148→        .filter(|t| looks_like_path(t))
149→        .collect()
150→}
