152→/// Extract `@`-mentioned file paths from turn text.
153→///
154→/// Users reference files with `@/absolute/path` syntax in prompts. This
155→/// function finds those mentions and normalizes them.
156→fn extract_at_mentions(turn_text: &str, project_dir: &str, project_root: &str) -> Vec<String> {
157→    let mut result = Vec::new();
158→    for token in turn_text.split_whitespace() {
159→        if let Some(path) = token.strip_prefix('@') {
160→            // Strip trailing punctuation that might cling to the mention
161→            let path = path.trim_end_matches(|c: char| {
162→                c == ',' || c == ';' || c == ':' || c == ')' || c == '?' || c == '!'
163→            });
164→            if path.is_empty() {
165→                continue;
166→            }
167→            if let Some(normalized) = normalize_path(path, project_dir, project_root) {
168→                result.push(normalized.into_owned());
169→            }
170→        }
171→    }
172→    result.sort();
173→    result.dedup();
174→    result
175→}
