177→/// Run the incremental ingest pipeline for a single session.
178→///
179→/// 1. Read new messages from the transcript starting at `last_line_index`.
180→/// 2. Insert raw entries into the `entries` table.
181→/// 3. If a provisional turn exists, delete it (CASCADE handles chunks + `file_mentions`).
182→/// 4. Process all turns: chunk -> embed -> store (turn + chunks + `file_mentions`).
183→/// 5. Update session state.
184→
185→/// Insert raw entries and PR links into the database.
186→fn insert_raw_data(
187→    conn: &Connection,
188→    session_id: &str,
189→    raw_entries: &[RawEntry],
190→    pr_links: &[PrLinkEntry],
191→) -> anyhow::Result<()> {
192→    for entry in raw_entries {
193→        insert_entry(
194→            conn,
195→            session_id,
196→            entry.line_index,
197→            &entry.entry_type,
198→            &entry.content,
199→            &entry.tool_summary,
200→            entry.timestamp.as_deref(),
201→        )?;
202→    }
203→    if !raw_entries.is_empty() {
204→        debug!(
205→            session_id = %session_id,
206→            count = raw_entries.len(),
207→            "Inserted raw entries"
208→        );
209→    }
210→    for pr_link in pr_links {
211→        insert_pr_link(
212→            conn,
213→            session_id,
214→            pr_link.pr_number,
215→            &pr_link.pr_url,
216→            &pr_link.pr_repository,
217→            &pr_link.timestamp,
218→        )?;
219→    }
220→    if !pr_links.is_empty() {
221→        debug!(
222→            session_id = %session_id,
223→            count = pr_links.len(),
224→            "Inserted PR links"
225→        );
226→    }
227→    Ok(())
228→}
