230→/// Process turns: chunk, embed, and store each turn in the database.
231→///
232→/// Returns `(last_line_index, new_provisional_start)` for session state update.
233→#[allow(clippy::too_many_arguments)]
234→fn process_turns(
235→    conn: &mut Connection,
236→    embedder: &mut Embedder,
237→    session_id: &str,
238→    turns: &[Turn],
239→    project_dir: &str,
240→    project_root: &str,
241→    tokenizer: &Tokenizer,
242→    initial_last_line: usize,
243→) -> anyhow::Result<(usize, Option<usize>)> {
244→    let mut last_line_index = initial_last_line;
245→    let mut new_provisional_start: Option<usize> = None;
246→
247→    for turn in turns {
248→        let chunks = chunk_turn(turn, tokenizer);
249→        debug!(
250→            session_id = %session_id,
251→            start_line = turn.start_line,
252→            chunk_count = chunks.len(),
253→            provisional = turn.provisional,
254→            "Chunked turn"
255→        );
256→        if chunks.is_empty() {
257→            continue;
258→        }
259→
260→        // Embed all chunks OUTSIDE the transaction (avoid holding write lock during inference)
261→        let texts: Vec<&str> = chunks.iter().map(|c| c.text.as_str()).collect();
262→        let embeddings = embedder.embed_batch(&texts).with_context(|| {
263→            format!(
264→                "Failed to embed chunks for turn at line {}",
265→                turn.start_line
266→            )
267→        })?;
268→
269→        // Transaction: upsert turn + insert chunks + insert file mentions
270→        let tx = conn.transaction()?;
271→
272→        let turn_id = upsert_turn(
273→            &tx,
274→            session_id,
275→            turn.start_line,
276→            turn.end_line,
277→            turn.provisional,
278→            &turn.full_text,
279→        )?;
280→
281→        for (chunk, embedding) in chunks.iter().zip(embeddings.iter()) {
282→            insert_chunk(&tx, turn_id, chunk.chunk_index, embedding)?;
283→        }
284→
285→        // Extract and store file mentions from tool summaries
286→        let file_paths = extract_file_paths(&turn.tool_summary, project_dir, project_root);
287→        for (file_path, tool_name) in &file_paths {
288→            insert_file_mention(&tx, turn_id, file_path, tool_name)?;
289→        }
290→
291→        // Extract and store @-mentioned file paths from user text
292→        let at_mentions = extract_at_mentions(&turn.full_text, project_dir, project_root);
293→        for file_path in &at_mentions {
294→            insert_file_mention(&tx, turn_id, file_path, "mention")?;
295→        }
296→
297→        tx.commit()?;
298→
299→        if !file_paths.is_empty() || !at_mentions.is_empty() {
300→            debug!(
301→                session_id = %session_id,
302→                start_line = turn.start_line,
303→                tool_files = file_paths.len(),
304→                at_mentions = at_mentions.len(),
305→                "Stored file mentions"
306→            );
307→        }
308→
309→        if turn.provisional {
310→            new_provisional_start = Some(turn.start_line);
311→        }
312→
313→        // Update last_line_index to be beyond all messages in this turn
314→        last_line_index = turn.end_line + 1;
315→    }
316→
317→    Ok((last_line_index, new_provisional_start))
318→}
