320→pub fn run_ingest(
321→    conn: &mut Connection,
322→    embedder: &mut Embedder,
323→    session_id: &str,
324→    transcript_path: &Path,
325→    project_dir: &str,
326→    project_root: &str,
327→) -> anyhow::Result<()> {
328→    let tokenizer = embedder.tokenizer().clone();
329→    // Load or create session
330→    let session = queries::get_session(conn, session_id)?;
331→    let (start_line, provisional_start) = if let Some(s) = &session {
332→        debug!(
333→            session_id = %session_id,
334→            last_line_index = s.last_line_index,
335→            provisional_turn_start = ?s.provisional_turn_start,
336→            last_compact_line_index = ?s.last_compact_line_index,
337→            "Loaded existing session"
338→        );
339→        (s.last_line_index, s.provisional_turn_start)
340→    } else {
341→        debug!(session_id = %session_id, "Creating new session");
342→        (0, None)
343→    };
344→
345→    // Parse new messages from the transcript starting at start_line.
346→    // If there's a provisional turn, re-read from its start to re-process it.
347→    let read_from = provisional_start.unwrap_or(start_line);
348→    let ParseResult {
349→        messages,
350→        pr_links,
351→        raw_entries,
352→    } = parse_transcript(transcript_path, read_from)?;
353→    debug!(
354→        session_id = %session_id,
355→        read_from = read_from,
356→        message_count = messages.len(),
357→        pr_link_count = pr_links.len(),
358→        raw_entry_count = raw_entries.len(),
359→        "Parsed transcript messages"
360→    );
361→    if messages.is_empty() && pr_links.is_empty() && raw_entries.is_empty() {
362→        debug!("No new data found in transcript");
363→        return Ok(());
364→    }
365→
366→    let existing_compact_line = session.as_ref().and_then(|s| s.last_compact_line_index);
367→    let base_session = Session {
368→        session_id: session_id.to_string(),
369→        transcript_path: transcript_path.to_string_lossy().to_string(),
370→        project_dir: project_dir.to_string(),
371→        ..Session::default()
372→    };
373→
374→    // Ensure session record exists (required for foreign keys)
375→    if session.is_none() {
376→        upsert_session(
377→            conn,
378→            &Session {
379→                last_line_index: read_from,
380→                ..base_session.clone()
381→            },
382→        )?;
383→    }
384→
385→    insert_raw_data(conn, session_id, &raw_entries, &pr_links)?;
386→
387→    // Group messages into turns
388→    let turns = group_into_turns(&messages);
389→    debug!(session_id = %session_id, turn_count = turns.len(), "Grouped messages into turns");
390→
391→    if turns.is_empty() {
392→        debug!("No turns formed from messages");
393→        // Still update session to advance past raw entries / PR links
394→        let last_line = raw_entries
395→            .iter()
396→            .map(|e| e.line_index)
397→            .chain(pr_links.iter().map(|p| p.line_index))
398→            .max()
399→            .map_or(read_from, |m| m + 1);
400→        upsert_session(
401→            conn,
402→            &Session {
403→                last_line_index: last_line,
404→                last_compact_line_index: existing_compact_line,
405→                ..base_session.clone()
406→            },
407→        )?;
408→        return Ok(());
409→    }
410→
411→    // If a provisional turn existed, delete it (CASCADE cleans chunks + file_mentions)
412→    if let Some(prov_line) = provisional_start {
413→        let deleted = delete_turn_at(conn, session_id, prov_line)?;
414→        debug!("Deleted {deleted} provisional turn at start_line={prov_line}");
415→    }
416→
417→    let (mut last_line_index, new_provisional_start) = process_turns(
418→        conn,
419→        embedder,
420→        session_id,
421→        &turns,
422→        project_dir,
423→        project_root,
424→        &tokenizer,
425→        read_from,
426→    )?;
427→
428→    // Messages are guaranteed non-empty: turns require at least one user-assistant pair.
429→    let max_message_line = messages.iter().map(|m| m.line_index).max().unwrap();
430→    last_line_index = last_line_index.max(max_message_line + 1);
431→
432→    // Upsert session state
433→    upsert_session(
434→        conn,
435→        &Session {
436→            last_line_index,
437→            provisional_turn_start: new_provisional_start,
438→            last_compact_line_index: existing_compact_line,
439→            ..base_session
440→        },
441→    )?;
442→
443→    let total = turns.len();
444→    let provisional = usize::from(new_provisional_start.is_some());
445→    let complete = total - provisional;
446→    info!(
447→        "Ingested {total} turns ({complete} complete, {provisional} provisional) for session {session_id}"
448→    );
449→
450→    Ok(())
451→}
