        let refs: Vec<&str> = lines.iter().map(String::as_str).collect();
        let transcript = write_transcript(tmp.path(), &refs);

        // Ingest twice
        run_ingest(
            &mut conn,
            &mut embedder,
            "s1",
            &transcript,
            "/tmp/p",
            "/tmp/p",
        )
        .unwrap();
        run_ingest(
            &mut conn,
            &mut embedder,
            "s1",
            &transcript,
            "/tmp/p",
            "/tmp/p",
        )
        .unwrap();

        let count: i64 = conn
            .query_row(
                "SELECT count(*) FROM pr_links WHERE session_id = 's1'",
                [],
                |row| row.get(0),
            )
            .unwrap();
        assert_eq!(count, 1);
    }
}

