    #[test]
    fn upsert_session_updates_last_compact_line_index() {
        let (_tmp, conn) = test_db();

        let session = Session {
            last_line_index: 100,
            last_compact_line_index: Some(50),
            ..make_session("s1")
        };
        upsert_session(&conn, &session).unwrap();

        let updated = Session {
            last_line_index: 200,
